void solve(int CASE)
{
	ll n; cin >> n;
	ll sum = 0;
	fa(i, 1, n) {
		ll x; cin >> x;
		sum += x;
	}
	ll ans = 0;
	fb(i, 30, 0) {
		ll now = (1ll << i);
		if (sum > n * (now - 1)) {
			ll tmp = min(n, sum / now);
			sum -= tmp * now;
			ans += now;
		}
	}
	cout << ans << endl;
	return;
}
